import heapq

def kClosest(points: list[list[int]], k: int) -> list[list[int]]:
    heap = []

    for point in points:
        x, y = point[0], point[1]
        squared_distance = x*x + y*y

        if len(heap) < k:
            heapq.heappush(heap, (-squared_distance, point))
        else:
            if -squared_distance > heap[0][0]:
                heapq.heappop(heap)
                heapq.heappush(heap, (-squared_distance, point))

    result = [item[1] for item in heap]
    return result
